import pino from 'pino';
import client from 'prom-client';
import { NodeSDK } from '@opentelemetry/sdk-node';
import { getNodeAutoInstrumentations } from '@opentelemetry/auto-instrumentations-node';

// logs: one JSON line per event - machines can read them
export const log = pino({ level: process.env.LOG_LEVEL ?? 'info' });

// metrics: counters/histograms scraped at /metrics
client.collectDefaultMetrics();
export const httpDuration = new client.Histogram({
  name: 'http_request_duration_seconds',
  help: 'request duration',
  labelNames: ['method', 'route', 'status'],
});
export const metricsText = () => client.register.metrics();

// traces: follow one request across services
new NodeSDK({ instrumentations: [getNodeAutoInstrumentations()] }).start();

import { jwtVerify, createRemoteJWKSet } from 'jose';

const JWKS = createRemoteJWKSet(new URL(process.env.OIDC_JWKS_URL!));

// returns the user claims, or throws 401
export async function requireUser(authHeader?: string) {
  const token = authHeader?.replace(/^Bearer /, '');
  if (!token) throw Object.assign(new Error('missing token'), { status: 401 });
  const { payload } = await jwtVerify(token, JWKS, {
    issuer: process.env.OIDC_ISSUER,
    audience: process.env.OIDC_AUDIENCE,
  });
  return payload; // { sub, email, roles, ... }
}

import { onLCP, onINP, onCLS } from 'web-vitals';

const send = (m: { name: string; value: number }) =>
  navigator.sendBeacon('/api/vitals', JSON.stringify(m));

onLCP(send); onINP(send); onCLS(send);

